import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { initialN5Data } from './data';

const INTERVALS = [10*60*1000, 24*60*60*1000, 3*24*60*60*1000, 7*24*60*60*1000, 30*24*60*60*1000];

export default function SkimmifyApp() {
  const [globalWords, setGlobalWords] = useState(() => {
      const saved = localStorage.getItem('skimmify-n5-v13');
          return saved ? JSON.parse(saved) : initialN5Data.map(w => ({ 
                ...w, isSaved: false, isHard: false, step: 0, nextReviewTime: 0 
                    }));
                      });

                        const [mode, setMode] = useState('menu');
                          const [selectedChunk100, setSelectedChunk100] = useState(null);
                            const [selectedChunk50, setSelectedChunk50] = useState(null);
                              const [listType, setListType] = useState(null);
                                const [snapshotIds, setSnapshotIds] = useState([]);
                                  const [sessionStats, setSessionStats] = useState({});
                                    const [queue, setQueue] = useState([]);
                                      const [currentWord, setCurrentWord] = useState(null);
                                        const [isFlipped, setIsFlipped] = useState(false);
                                          const [timeLeft, setTimeLeft] = useState(26000);
                                            const [startTime, setStartTime] = useState(0);
                                              const [endTime, setEndTime] = useState(0);
                                                const [feedbackMsg, setFeedbackMsg] = useState('');
                                                  const [isProcessing, setIsProcessing] = useState(false);
                                                    const feedbackTimer = useRef(null);
                                                      const actionTimerRef = useRef(null);

                                                        useEffect(() => { localStorage.setItem('skimmify-n5-v13', JSON.stringify(globalWords)); }, [globalWords]);

                                                          const speak = (text) => {
                                                              if (!window.speechSynthesis) return;
                                                                  window.speechSynthesis.cancel();
                                                                      const u = new SpeechSynthesisUtterance(text); u.lang = 'ja-JP'; u.rate = 0.9;
                                                                          window.speechSynthesis.speak(u);
                                                                            };

                                                                              const showFeedback = (msg) => {
                                                                                  setFeedbackMsg(msg);
                                                                                      if (feedbackTimer.current) clearTimeout(feedbackTimer.current);
                                                                                          feedbackTimer.current = setTimeout(() => setFeedbackMsg(''), 1500);
                                                                                            };

                                                                                              const initStudy = (ids, source) => {
                                                                                                  const initialStats = {};
                                                                                                      ids.forEach(id => { initialStats[id] = { cMastered: 0, cForgot: 0, completed: false, lastAnswer: null }; });
                                                                                                          setSessionStats(initialStats);
                                                                                                              const sortedQueue = [...ids].sort((a, b) => a - b);
                                                                                                                  setQueue(sortedQueue); setCurrentWord(globalWords.find(w => w.id === sortedQueue[0]));
                                                                                                                      setMode('study'); setStartTime(Date.now()); setIsFlipped(false); setTimeLeft(26000); setIsProcessing(false);
                                                                                                                        };

                                                                                                                          useEffect(() => {
                                                                                                                              if (mode !== 'study' || !currentWord || isProcessing) return;
                                                                                                                                  if (timeLeft <= 0) { handleAction('forgot'); return; }
                                                                                                                                      const t = setInterval(() => setTimeLeft(p => Math.max(p - 100, 0)), 100);
                                                                                                                                          return () => clearInterval(t);
                                                                                                                                            }, [timeLeft, mode, currentWord, isProcessing]);

                                                                                                                                              const applyStatsAndNext = (action) => {
                                                                                                                                                  const id = currentWord.id; const wordIdx = globalWords.findIndex(w => w.id === id);
                                                                                                                                                      let newGlobal = [...globalWords]; let target = { ...newGlobal[wordIdx] };
                                                                                                                                                          const stats = sessionStats[id]; let newStats = { ...stats, lastAnswer: action };

                                                                                                                                                              if (action === 'mastered') {
                                                                                                                                                                    newStats.cMastered += 1; newStats.cForgot = 0;
                                                                                                                                                                          if (newStats.cMastered === 3) {
                                                                                                                                                                                  newStats.completed = true; target.step = (target.step || 0) + 1;
                                                                                                                                                                                          target.nextReviewTime = Date.now() + INTERVALS[Math.min(target.step - 1, 4)];
                                                                                                                                                                                                  target.isHard = false; showFeedback('학습완료!');
                                                                                                                                                                                                        } else { showFeedback(`${newStats.cMastered}번 연속 정답!`); }
                                                                                                                                                                                                            } else {
                                                                                                                                                                                                                  newStats.cForgot += 1; newStats.cMastered = 0;
                                                                                                                                                                                                                        if (newStats.cForgot === 3) {
                                                                                                                                                                                                                                target.isHard = true; target.step = 0;
                                                                                                                                                                                                                                        target.nextReviewTime = Date.now() + INTERVALS[0];
                                                                                                                                                                                                                                                showFeedback('모르겠는 단어에 추가됨'); newStats.cForgot = 0;
                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                              newGlobal[wordIdx] = target; setSessionStats({ ...sessionStats, [id]: newStats }); setGlobalWords(newGlobal);
                                                                                                                                                                                                                                                                  setTimeout(() => {
                                                                                                                                                                                                                                                                        const nextQ = queue.slice(1);
                                                                                                                                                                                                                                                                              if (nextQ.length > 0) { setQueue(nextQ); setCurrentWord(newGlobal.find(w => w.id === nextQ[0])); } 
                                                                                                                                                                                                                                                                                    else {
                                                                                                                                                                                                                                                                                            const uncompleted = Object.keys(sessionStats).filter(k => !sessionStats[k].completed).map(Number);
                                                                                                                                                                                                                                                                                                    if (uncompleted.length === 0) { 
                                                                                                                                                                                                                                                                                                              setEndTime(Date.now()); 
                                                                                                                                                                                                                                                                                                                        setMode('complete'); 
                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                            // API 예약 발송 로직
                                                                                                                                                                                                                                                                                                                                                      if (window.OneSignalDeferred) {
                                                                                                                                                                                                                                                                                                                                                                  window.OneSignalDeferred.push(async function(OneSignal) {
                                                                                                                                                                                                                                                                                                                                                                                const subId = OneSignal.User.PushSubscription.id;
                                                                                                                                                                                                                                                                                                                                                                                              if (!subId) return;

                                                                                                                                                                                                                                                                                                                                                                                                            const APP_ID = "6d233f88-93e6-40fa-af19-3ec8dfc38d34";
                                                                                                                                                                                                                                                                                                                                                                                                                          const REST_API_KEY = "os_v2_app_nurt7cet4zapvlyzh3en7q4ngq7l2gr7tcausmv5iuh7hqulom6epsz3xcmfgpchksh32cjvucd5lvteu7apc2vegvlqv63dqwlc5ky";

                                                                                                                                                                                                                                                                                                                                                                                                                                        const getSendAfter = (minutes) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                        const d = new Date(new Date().getTime() + minutes * 60000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return d.toUTCString() + " -0000"; 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const schedules = [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { title: "⚡ 10분 복습 알림", msg: "방금 학습한 단어들의 1차 복습 타이밍입니다. 지금 바로 스키밍하세요!", delay: 10 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { title: "⏳ 2시간 복습 알림", msg: "2시간 전 학습한 단어들의 2차 복습 타이밍입니다. 기억이 흩어지기 전에 빠르게 스키밍하세요!", delay: 120 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { title: "💡 1일 복습 알림", msg: "어제 학습한 단어들의 3차 복습 타이밍입니다. 단기 기억을 장기 기억으로 넘기기 위해 스키밍하세요!", delay: 1440 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { title: "🧠 7일 복습 알림", msg: "일주일 전 학습한 단어들의 4차 복습 타이밍입니다. 잊지 않도록 가볍게 다시 한번 스키밍하세요!", delay: 10080 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { title: "🏆 30일 복습 알림", msg: "한 달 전 학습한 단어들의 최종 복습 타이밍입니다. 마지막 스키밍으로 완벽하게 마스터하세요!", delay: 43200 }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                schedules.forEach(schedule => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                fetch("https://onesignal.com/api/v1/notifications", {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  method: "POST",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        "Content-Type": "application/json; charset=utf-8",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "Authorization": `Basic ${REST_API_KEY}`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                body: JSON.stringify({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    app_id: APP_ID,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        include_subscription_ids: [subId],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            headings: { "en": schedule.title, "ko": schedule.title },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                contents: { "en": schedule.msg, "ko": schedule.msg },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    send_after: getSendAfter(schedule.delay)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }).catch(e => console.error(e));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          else { setQueue(uncompleted); setCurrentWord(newGlobal.find(w => w.id === uncompleted[0])); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      setIsFlipped(false); setTimeLeft(26000); setIsProcessing(false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }, 150);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const handleAction = (action) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (isProcessing) return; setIsProcessing(true); speak(currentWord.reading);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (action === 'forgot') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setIsFlipped(true); actionTimerRef.current = setTimeout(() => { actionTimerRef.current = null; applyStatsAndNext(action); }, 1500);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } else { applyStatsAndNext(action); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const skipDelay = () => { if (isProcessing && isFlipped && actionTimerRef.current) { clearTimeout(actionTimerRef.current); actionTimerRef.current = null; applyStatsAndNext('forgot'); } };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const toggleSaveStudy = (e) => { e.stopPropagation(); setGlobalWords(prev => prev.map(w => w.id === currentWord.id ? { ...w, isSaved: !w.isSaved } : w)); setCurrentWord(prev => ({ ...prev, isSaved: !prev.isSaved })); };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const toggleSaveList = (id) => { setGlobalWords(prev => prev.map(w => w.id === id ? { ...w, isSaved: !w.isSaved } : w)); };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const formatTime = (ms) => { const s = Math.floor(ms / 1000); return `${Math.floor(s / 60)}분 ${s % 60}초`; };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (mode === 'menu') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const sC = globalWords.filter(w => w.isSaved).length; const hC = globalWords.filter(w => w.isHard).length;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const rW = globalWords.filter(w => w.nextReviewTime > 0 && w.nextReviewTime < Date.now());

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (selectedChunk100 === null) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const chunk100 = Math.ceil(globalWords.length / 100);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex flex-col items-center h-[100dvh] bg-slate-50 px-6 py-12 overflow-y-auto"><h1 className="text-3xl font-black text-gray-800 mb-8">N5 단어 학습장</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="w-full max-w-sm space-y-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {rW.length > 0 && (<button onClick={() => initStudy(rW.map(w => w.id), 'review')} className="w-full py-5 bg-green-600 text-white rounded-2xl shadow-lg text-xl font-black active:scale-95 mb-4">오늘의 복습 ({rW.length})</button>)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {Array.from({ length: chunk100 }, (_, i) => i * 100).map(start => (<button key={start} onClick={() => setSelectedChunk100(start)} className="w-full py-4 bg-white rounded-2xl shadow-sm text-lg font-bold text-gray-700 active:scale-95 border border-gray-100">{start + 1} ~ {Math.min(start + 100, globalWords.length)} 구간</button>))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          } else if (selectedChunk50 === null) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const chunk50 = Math.ceil(Math.min(100, globalWords.length - selectedChunk100) / 50);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex flex-col items-center h-[100dvh] bg-slate-50 px-6 py-12 overflow-y-auto"><div className="w-full max-w-sm relative flex justify-center items-center mb-8"><button onClick={() => setSelectedChunk100(null)} className="absolute left-0 px-4 py-2 bg-gray-200 rounded-lg font-bold text-gray-600">← 뒤로</button><h1 className="text-xl font-black text-gray-800">{selectedChunk100 + 1}~{Math.min(selectedChunk100 + 100, globalWords.length)}</h1></div><div className="w-full max-w-sm space-y-3">{Array.from({ length: chunk50 }, (_, i) => selectedChunk100 + i * 50).map(start => (<button key={start} onClick={() => setSelectedChunk50(start)} className="w-full py-4 bg-white rounded-2xl shadow-sm text-lg font-bold text-gray-700 border border-gray-100">{start + 1} ~ {Math.min(start + 50, globalWords.length)} 구간</button>))}</div></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const chunk10 = Math.ceil(Math.min(50, globalWords.length - selectedChunk50) / 10);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex flex-col items-center h-[100dvh] bg-slate-50 px-6 py-12 overflow-y-auto"><div className="w-full max-w-sm relative flex justify-center items-center mb-8"><button onClick={() => setSelectedChunk50(null)} className="absolute left-0 px-4 py-2 bg-gray-200 rounded-lg font-bold text-gray-600">← 뒤로</button><h1 className="text-xl font-black text-gray-800">{selectedChunk50 + 1}~{Math.min(selectedChunk50 + 50, globalWords.length)}</h1></div><div className="w-full max-w-sm space-y-3">{Array.from({ length: chunk10 }, (_, i) => selectedChunk50 + i * 10).map(start => (<button key={start} onClick={() => initStudy(globalWords.filter(w => w.id > start && w.id <= start + 10).map(w => w.id), 'range')} className="w-full py-4 bg-white rounded-2xl shadow-sm text-lg font-bold text-gray-700 border border-gray-100">{start + 1} ~ {Math.min(start + 10, globalWords.length)} 스키밍</button>))}<div className="pt-4 border-t border-gray-200 mt-4 space-y-3"><button onClick={() => { setSnapshotIds(globalWords.filter(w => w.isSaved).map(w => w.id)); setListType('saved'); setMode('list'); }} disabled={sC === 0} className={`w-full py-4 rounded-2xl shadow-sm text-lg font-black ${sC > 0 ? 'bg-blue-50 text-blue-600 border border-blue-100' : 'bg-gray-100 text-gray-400 opacity-50'}`}>저장한 단어 학습 ({sC})</button><button onClick={() => { setSnapshotIds(globalWords.filter(w => w.isHard).map(w => w.id)); setListType('hard'); setMode('list'); }} disabled={hC === 0} className={`w-full py-4 rounded-2xl shadow-sm text-lg font-black ${hC > 0 ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-gray-100 text-gray-400 opacity-50'}`}>잘 모르는 단어 학습 ({hC})</button></div></div></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (mode === 'list') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const lW = snapshotIds.map(id => globalWords.find(w => w.id === id)).filter(Boolean).sort((a,b) => a.id - b.id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex flex-col h-[100dvh] bg-slate-50"><header className="px-6 py-6 border-b border-gray-200 bg-white flex justify-between items-center sticky top-0 z-10"><h2 className="text-xl font-bold text-gray-800">{listType === 'saved' ? '저장한 단어 리스트' : '잘 모르는 단어 리스트'}</h2><button onClick={() => setMode('menu')} className="px-3 py-1 bg-gray-100 rounded-lg text-sm font-bold text-gray-600">뒤로</button></header><div className="flex-1 overflow-y-auto p-4 space-y-2">{lW.map(w => (<div key={w.id} className="flex justify-between items-center p-4 bg-white rounded-xl shadow-sm border border-gray-100"><div className="flex items-center gap-4"><span className="text-gray-400 font-bold w-6">{w.id}</span><div><div className="text-sm text-blue-500 font-bold">{w.reading}</div><div className="text-xl font-black text-gray-800">{w.word}</div></div></div><div className="flex items-center gap-3"><div className="text-base font-bold text-gray-600">{w.meaning}</div><button onClick={() => toggleSaveList(w.id)} className={`text-3xl ${w.isSaved ? 'text-yellow-400' : 'text-gray-200'}`}>★</button></div></div>))}</div><div className="p-4 bg-white border-t border-gray-200 pb-8"><button onClick={() => { const vId = globalWords.filter(w => listType === 'saved' ? w.isSaved : w.isHard).map(w => w.id); initStudy(vId, listType); }} className="w-full py-4 bg-blue-600 text-white rounded-2xl text-lg font-bold shadow-lg">학습 시작하기</button></div></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (mode === 'complete') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="flex flex-col items-center justify-center h-[100dvh] bg-slate-50 px-6"><div className="w-full max-w-sm bg-white p-8 rounded-3xl shadow-xl text-center"><h2 className="text-3xl font-black text-blue-600 mb-2">학습 완료!</h2><p className="text-gray-500 font-medium mb-8">소요 시간: <span className="font-bold text-gray-800">{formatTime(endTime - startTime)}</span></p><button onClick={() => setMode('menu')} className="w-full py-3 bg-gray-100 text-gray-700 rounded-xl font-bold">메뉴로 돌아가기</button></div></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (!currentWord) return null;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="h-[100dvh] w-full bg-slate-50 flex flex-col relative overflow-hidden select-none" onClick={skipDelay}><div className="absolute top-0 left-0 w-full h-1.5 bg-gray-200 z-50"><div className="h-full bg-blue-600 transition-all" style={{ width: `${(timeLeft/26000)*100}%` }} /></div><button onClick={() => setMode('menu')} className="absolute top-6 left-6 z-50 px-4 py-2 bg-white rounded-full shadow-sm text-sm font-bold text-gray-500">종료</button><main className="flex-1 flex flex-col items-center justify-center p-4"><AnimatePresence>{feedbackMsg && (<motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className={`absolute top-20 z-50 px-6 py-3 rounded-full shadow-lg font-bold text-white ${feedbackMsg.includes('정답') || feedbackMsg.includes('완료') || feedbackMsg.includes('단계') ? 'bg-green-500' : 'bg-red-500'}`}>{feedbackMsg}</motion.div>)}</AnimatePresence><AnimatePresence mode="wait"><motion.div key={currentWord.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0, rotateY: isFlipped ? 180 : 0 }} exit={{ opacity: 0, x: isFlipped ? 100 : -100 }} onClick={() => { if(!isFlipped) speak(currentWord.reading); setIsFlipped(!isFlipped); }} drag="x" dragConstraints={{ left: 0, right: 0 }} onDragEnd={(e, { offset }) => { if (offset.x > 60) handleAction('mastered'); else if (offset.x < -60) handleAction('forgot'); }} className="w-80 h-[420px] relative shadow-2xl rounded-3xl cursor-pointer" style={{ transformStyle: 'preserve-3d' }}><div className="absolute inset-0 flex flex-col justify-center items-center bg-white rounded-3xl" style={{ backfaceVisibility: 'hidden' }}><div className="absolute top-5 left-5 text-gray-300 font-black text-lg">No.{currentWord.id}</div><button onClick={toggleSaveStudy} className={`absolute top-4 right-4 p-3 rounded-full text-3xl ${currentWord.isSaved ? 'text-yellow-400' : 'text-gray-200'} active:scale-75`} style={{lineHeight: 1}}>★</button><h1 className="text-6xl font-bold text-gray-800">{currentWord.word}</h1><p className="mt-8 px-5 py-2 bg-gray-50 text-gray-400 text-sm font-bold rounded-full">터치하여 발음 듣기</p></div><div className="absolute inset-0 flex flex-col justify-center items-center bg-blue-50 rounded-3xl border border-blue-100" style={{ backfaceVisibility: 'hidden', transform: 'rotateY(180deg)' }}><button onClick={toggleSaveStudy} className={`absolute top-4 right-4 p-3 rounded-full text-3xl ${currentWord.isSaved ? 'text-yellow-400' : 'text-blue-200'} active:scale-75`} style={{lineHeight: 1}}>★</button><h2 className="text-3xl text-blue-600 font-bold mb-4">{currentWord.reading}</h2><h3 className="text-4xl font-black text-gray-800">{currentWord.meaning}</h3><p className="absolute bottom-8 w-full text-center text-xs text-gray-400 font-bold"><span className="text-red-400">← 몰라요</span> &nbsp;|&nbsp; <span className="text-green-500">알아요 →</span></p></div></motion.div></AnimatePresence><div className="flex gap-8 mt-12 z-10"><button onClick={(e) => { e.stopPropagation(); handleAction('forgot'); }} disabled={isProcessing} className="w-16 h-16 bg-white rounded-full shadow-lg text-red-500 text-2xl font-bold active:scale-90 disabled:opacity-50">✕</button><button onClick={(e) => { e.stopPropagation(); handleAction('mastered'); }} disabled={isProcessing} className="w-16 h-16 bg-white rounded-full shadow-lg text-green-500 text-2xl font-bold active:scale-90 disabled:opacity-50">◯</button></div></main></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          